*----------------------------------------------------------------------------;
* Program: t1_1_sdtm_relrec_gen_010.sas
* Purpose: Create SDTM RELREC (Related Records) domain dataset
* Input: Raw related records data (raw.relrec)
* Output: sdtm.relrec (SAS V5 XPORT format)
*----------------------------------------------------------------------------;

*--- Setup ---;
libname raw "&rawpath";
libname sdtm "&sdtmpath";

*--- Read raw data ---;
data relrec_raw;
  set raw.relrec;
run;

*--- Sort by subject and sequence ---;
proc sort data=relrec_raw out=relrec_sorted;
  by usubjid seq;
run;

*--- Derive RELRECSEQ (sequential numbering per subject) ---;
data relrec_seq;
  set relrec_sorted;
  by usubjid;
  retain relrecseq;
  if first.usubjid then relrecseq = 0;
  relrecseq + 1;
run;

*--- Map variables and apply attributes ---;
data sdtm.relrec (label="Related Records");
  length
    studyid $40
    domain $8
    usubjid $40
    relrecseq 8
    rdomain $8
    idvar $8
    idvarval $200
    reltype $2
    relid $20
  ;
  label
    studyid  = "Study Identifier"
    domain   = "Domain Abbreviation"
    usubjid  = "Unique Subject Identifier"
    relrecseq= "Sequence Number"
    rdomain  = "Related Domain Abbreviation"
    idvar    = "Identifying Variable"
    idvarval = "Identifying Variable Value"
    reltype  = "Relationship Type"
    relid    = "Relationship Identifier"
  ;

  set relrec_seq;

  *--- Assign domain constant ---;
  domain = "RELREC";

  *--- Map IDVAR and IDVARVAL based on relationship type ---;
  *--- For simplicity, assume IDVAR is the variable name and IDVARVAL is the value ---;
  *--- In practice, this would be derived from source data ---;
  if rdomain = "AE" then do;
    idvar = "AESEQ";
    idvarval = put(aeseq, best.);
  end;
  else if rdomain = "CM" then do;
    idvar = "CMSEQ";
    idvarval = put(cmseq, best.);
  end;
  else if rdomain = "MH" then do;
    idvar = "MHSEQ";
    idvarval = put(mhseq, best.);
  end;
  else if rdomain = "LB" then do;
    idvar = "LBSEQ";
    idvarval = put(lbseq, best.);
  end;
  else if rdomain = "VS" then do;
    idvar = "VSSEQ";
    idvarval = put(vsseq, best.);
  end;
  else if rdomain = "EX" then do;
    idvar = "EXSEQ";
    idvarval = put(exseq, best.);
  end;
  else if rdomain = "EG" then do;
    idvar = "EGSEQ";
    idvarval = put(egseq, best.);
  end;
  else if rdomain = "QS" then do;
    idvar = "QSSEQ";
    idvarval = put(qsseq, best.);
  end;
  else if rdomain = "SC" then do;
    idvar = "SCSEQ";
    idvarval = put(scseq, best.);
  end;
  else if rdomain = "SU" then do;
    idvar = "SUSEQ";
    idvarval = put(suseq, best.);
  end;
  else if rdomain = "DV" then do;
    idvar = "DVSEQ";
    idvarval = put(dvseq, best.);
  end;
  else if rdomain = "DS" then do;
    idvar = "DSSEQ";
    idvarval = put(dsseq, best.);
  end;
  else if rdomain = "HO" then do;
    idvar = "HOSEQ";
    idvarval = put(hoseq, best.);
  end;
  else if rdomain = "PR" then do;
    idvar = "PRSEQ";
    idvarval = put(prseq, best.);
  end;
  else if rdomain = "RS" then do;
    idvar = "RSSEQ";
    idvarval = put(rsseq, best.);
  end;
  else if rdomain = "SS" then do;
    idvar = "SSSEQ";
    idvarval = put(ssseq, best.);
  end;
  else if rdomain = "TU" then do;
    idvar = "TUSEQ";
    idvarval = put(tuseq, best.);
  end;
  else if rdomain = "TR" then do;
    idvar = "TRSEQ";
    idvarval = put(trseq, best.);
  end;
  else if rdomain = "TA" then do;
    idvar = "TASEQ";
    idvarval = put(taseq, best.);
  end;
  else if rdomain = "TE" then do;
    idvar = "TESEQ";
    idvarval = put(teseq, best.);
  end;
  else if rdomain = "TV" then do;
    idvar = "TVSEQ";
    idvarval = put(tvseq, best.);
  end;
  else if rdomain = "TI" then do;
    idvar = "TISEQ";
    idvarval = put(tiseq, best.);
  end;
  else if rdomain = "CO" then do;
    idvar = "COSEQ";
    idvarval = put(cosq, best.);
  end;
  else if rdomain = "FA" then do;
    idvar = "FASEQ";
    idvarval = put(faseq, best.);
  end;
  else if rdomain = "CP" then do;
    idvar = "CPSEQ";
    idvarval = put(cpseq, best.);
  end;
  else if rdomain = "EC" then do;
    idvar = "ECSEQ";
    idvarval = put(ecseq, best.);
  end;
  else if rdomain = "MB" then do;
    idvar = "MBSEQ";
    idvarval = put(mbseq, best.);
  end;
  else if rdomain = "MI" then do;
    idvar = "MISEQ";
    idvarval = put(miseq, best.);
  end;
  else if rdomain = "PC" then do;
    idvar = "PCSEQ";
    idvarval = put(pcseq, best.);
  end;
  else if rdomain = "PP" then do;
    idvar = "PPSEQ";
    idvarval = put(ppseq, best.);
  end;
  else if rdomain = "RE" then do;
    idvar = "RESEQ";
    idvarval = put(reseq, best.);
  end;
  else if rdomain = "RP" then do;
    idvar = "RPSEQ";
    idvarval = put(rpseq, best.);
  end;
  else if rdomain = "SR" then do;
    idvar = "SRSEQ";
    idvarval = put(srseq, best.);
  end;
  else if rdomain = "SV" then do;
    idvar = "SVSEQ";
    idvarval = put(svseq, best.);
  end;
  else if rdomain = "VS" then do;
    idvar = "VSSEQ";
    idvarval = put(vsseq, best.);
  end;
  else do;
    idvar = "";
    idvarval = "";
  end;

  *--- Assign RELTYPE based on source data ---;
  *--- Default to "1" (one-to-one) if not specified ---;
  if missing(reltype) then reltype = "1";

  *--- Assign RELID based on source data ---;
  *--- If missing, create a unique identifier ---;
  if missing(relid) then relid = catx("-", usubjid, rdomain, put(relrecseq, z3.));

  *--- Keep only required variables ---;
  keep studyid domain usubjid relrecseq rdomain idvar idvarval reltype relid;
run;

*--- Sort final dataset ---;
proc sort data=sdtm.relrec;
  by usubjid relrecseq;
run;

*--- Create XPORT transport file ---;
libname xportout xport "&outpath/sdtm_relrec.xpt";
data xportout.relrec;
  set sdtm.relrec;
run;
libname xportout clear;

*--- End of program ---;
